import{_ as e,o as r,c as i,a2 as t}from"./chunks/framework.BEgbRHOA.js";const _=JSON.parse('{"title":"Панель менеджера (xcourier_manager)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-manager/index.md","filePath":"guide/xcourier-manager/index.md","lastUpdated":1775746985000}'),o={name:"guide/xcourier-manager/index.md"};function l(n,a,d,c,s,u){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="панель-менеджера-xcourier-manager" tabindex="-1">Панель менеджера (xcourier_manager) <a class="header-anchor" href="#панель-менеджера-xcourier-manager" aria-label="Permalink to &quot;Панель менеджера (xcourier_manager)&quot;">​</a></h1><p>Мобильное приложение для менеджеров магазинов. Позволяет обрабатывать заказы и управлять ассортиментом товаров.</p><h2 id="для-кого" tabindex="-1">Для кого <a class="header-anchor" href="#для-кого" aria-label="Permalink to &quot;Для кого&quot;">​</a></h2><p>Сотрудники магазинов, ответственные за приём и сборку заказов, а также за актуальность каталога товаров.</p><h2 id="основные-возможности" tabindex="-1">Основные возможности <a class="header-anchor" href="#основные-возможности" aria-label="Permalink to &quot;Основные возможности&quot;">​</a></h2><ul><li>Просмотр и обработка входящих заказов в реальном времени</li><li>Смена статуса заказа по мере обработки</li><li>Редактирование заказа (замена товаров, изменение количества)</li><li>Управление каталогом товаров (добавление, редактирование, удаление)</li><li>Управление категориями товаров</li><li>Push-уведомления о новых заказах</li></ul><h2 id="авторизация" tabindex="-1">Авторизация <a class="header-anchor" href="#авторизация" aria-label="Permalink to &quot;Авторизация&quot;">​</a></h2><p>Менеджер входит по email и паролю. Каждый менеджер привязан к конкретному магазину (<code>storeId</code>) и видит только заказы и товары своего магазина.</p><p>Если аккаунт менеджера заблокирован администратором (<code>isActive: false</code>), он перенаправляется на экран блокировки и не может пользоваться приложением.</p><h2 id="навигация" tabindex="-1">Навигация <a class="header-anchor" href="#навигация" aria-label="Permalink to &quot;Навигация&quot;">​</a></h2><p>Приложение использует боковое меню (Drawer) с двумя основными разделами:</p><ul><li><strong>Заказы</strong> — список активных и архивных заказов</li><li><strong>Товары</strong> — каталог товаров магазина</li></ul>',12)])])}const m=e(o,[["render",l]]);export{_ as __pageData,m as default};
